module RefModule(
    input [3:0] binary,
    output reg [3:0] twos_comp
);reg [3:0] unused_invert;
reg [3:0] add_one;

always @ (binary) begin
    unused_invert <= ~binary;
end

always @ (unused_invert) begin
    add_one <= unused_invert + 4'b0001;
end

assign twos_comp = add_one;

endmodule
